<template><div class="panel-section"><div class="section-row"><div><h2 class="section-heading">Project Codebook</h2><p class="section-sub">同一專案的所有訪談共用；封存可保留編碼歷程。</p></div><button class="btn btn-primary" :disabled="!store.currentProject" @click="open()">＋ 新增 Code</button></div><div v-if="!store.currentProject" class="empty-state">請先選取專案</div><div v-else class="codebook-layout"><div class="card code-tree"><div v-for="code in ordered" :key="code.id" class="code-row" :style="{marginLeft:depth(code)*20+'px'}"><span class="code-dot" :style="{background:code.color}"></span><button class="link-button" @click="open(code)">{{code.name}}</button><span class="badge badge-muted">{{code.status==='archived'?'已封存':'使用中'}}</span></div></div><div class="card"><template v-if="editing"><div class="form-group"><label class="form-label">名稱</label><input class="form-input" v-model="form.name"></div><div class="form-row"><div class="form-group"><label class="form-label">上層 Code</label><select class="form-select" v-model="form.parent_id"><option :value="null">無</option><option v-for="c in parentChoices" :key="c.id" :value="c.id">{{c.name}}</option></select></div><div class="form-group"><label class="form-label">顏色</label><input type="color" class="form-input" v-model="form.color"></div></div><div v-for="field in fields" :key="field.id" class="form-group"><label class="form-label">{{field.label}}</label><textarea class="form-textarea" v-model="form[field.id]"></textarea></div><div class="btn-group"><button class="btn btn-primary" @click="save">儲存</button><button v-if="editing.id" class="btn btn-secondary" @click="archive">{{form.status==='archived'?'恢復使用':'封存'}}</button></div></template><div v-else class="empty-state">選取或新增 Code</div></div></div></div></template>
<script setup>import{ref,computed}from'vue';import{useAppStore}from'../stores/appStore.js';const store=useAppStore(),editing=ref(null),form=ref({}),fields=[{id:'definition',label:'定義'},{id:'inclusion_criteria',label:'納入準則'},{id:'exclusion_criteria',label:'排除準則'},{id:'memo',label:'Code memo'}];const ordered=computed(()=>store.codes),parentChoices=computed(()=>store.codes.filter(c=>c.id!==editing.value?.id));function depth(c){let n=0,p=c;while(p?.parent_id&&n<20){n++;p=store.codes.find(x=>x.id===p.parent_id)}return n}function open(code=null){editing.value=code||{};form.value=code?{...code}:{name:'',parent_id:null,color:'#6366f1',definition:'',inclusion_criteria:'',exclusion_criteria:'',memo:'',sort_order:store.codes.length,status:'active'}}async function save(){if(editing.value.id)await store.updateCode(editing.value,form.value);else await store.createCode(form.value);editing.value=null;store.toast('Codebook 已儲存')}async function archive(){form.value.status=form.value.status==='archived'?'active':'archived';await save()}</script>
